import React from "react";
import { useLocation, useNavigate } from "react-router-dom";
import Topnav from "../components/Topnav";
import Footer from "../components/Footer";

function Result() {
  const navigate = useNavigate();
  const location = useLocation();

  const {
    gem_prediction = "Unknown",
    gem_confidence = 0,
    shape_prediction,
    shape_confidence,
    image,
    show_shape = false,
  } = location.state || {};

  const gemConfidencePercent = (gem_confidence * 100).toFixed(1);
  const shapeConfidencePercent = show_shape && shape_confidence
    ? (shape_confidence * 100).toFixed(1)
    : null;

  return (
    <>
      <Topnav />

      <main className="min-h-screen bg-gradient-to-b from-[#0a1425] via-[#0f1a36] to-[#0a1425] text-slate-100 py-12 px-4 sm:px-6 lg:px-8">
        <div className="max-w-4xl mx-auto">
          {/* Header */}
          <div className="text-center mb-10 sm:mb-14">
            <h1 className="text-3xl sm:text-4xl md:text-5xl font-bold tracking-tight text-[#60a5fa] mb-3">
              Analysis Result
            </h1>
            <p className="text-base sm:text-lg text-slate-400">
              Gem identification powered by AI
            </p>
          </div>

          {/* Main result container */}
          <div className="bg-[#111d38]/80 backdrop-blur-sm border border-[#1e40af]/40 rounded-2xl sm:rounded-3xl overflow-hidden shadow-2xl shadow-black/50">
            {/* Image section – controlled size */}
            {image && (
              <div className="relative mx-auto max-w-lg w-full px-6 pt-8 pb-4 sm:pt-10 sm:pb-6">
                <div className="aspect-square rounded-2xl overflow-hidden bg-black/50 border border-[#1e40af]/30 shadow-inner">
                  <img
                    src={URL.createObjectURL(image)}
                    alt={gem_prediction}
                    className="w-full h-full object-contain transition-transform duration-500 hover:scale-[1.03]"
                  />
                </div>
              </div>
            )}

            {/* Result information */}
            <div className="px-6 pb-10 sm:px-10 sm:pb-12 text-center">
              <h2 className="text-4xl sm:text-5xl md:text-6xl font-extrabold text-[#60a5fa] mb-4 tracking-tight">
                {gem_prediction}
              </h2>

              <div className="space-y-6 sm:space-y-8 mt-6 sm:mt-8">
                {/* Gem confidence */}
                <div className="inline-block">
                  <div className="text-slate-300 text-base sm:text-lg mb-1">
                    Gem Identification
                  </div>
                  <div className="px-6 py-2.5 bg-[#1e40af]/40 rounded-full text-[#60a5fa] font-semibold text-lg sm:text-xl">
                    {gemConfidencePercent}%
                  </div>
                </div>

                {/* Shape / Cut (conditional) */}
                {show_shape && shape_prediction && (
                  <div className="inline-block">
                    <div className="text-slate-300 text-base sm:text-lg mb-1">
                      Shape / Cut
                    </div>
                    <div className="px-6 py-2.5 bg-[#1e40af]/40 rounded-full text-[#60a5fa] font-semibold text-lg sm:text-xl">
                      {shapeConfidencePercent}%
                    </div>
                  </div>
                )}
              </div>

              {/* Action button */}
              <button
                onClick={() => navigate("/imageuploader")}
                className="mt-10 sm:mt-14 px-8 sm:px-12 py-3.5 sm:py-4 bg-[#3b82f6] hover:bg-[#2563eb] text-white text-base sm:text-lg font-semibold rounded-full transition-all duration-300 shadow-lg shadow-[#3b82f6]/30 hover:shadow-xl hover:shadow-[#3b82f6]/50 transform hover:scale-105 focus:outline-none focus:ring-4 focus:ring-[#60a5fa]/40"
              >
                Analyze Another Gem
              </button>
            </div>
          </div>

          {/* Small disclaimer */}
          <p className="text-center text-slate-500 mt-8 sm:mt-10 text-sm sm:text-base">
            This is an AI-generated estimate • Professional gemological appraisal recommended for valuable items
          </p>
        </div>
      </main>

      <Footer />
    </>
  );
}

export default Result;
